#include<bits/stdc++.h>using namespace std;int a[100005];int ans[100005][2];int main(){    ios::sync_with_stdio(false);    cin.tie(0);    cout.tie(0);    int t;    cin>>t;    while(t--){		int n;		cin>>n;		bool b=true;		bool c=false;		for(int i=1;i<=n;i++){			cin>>a[i];			if(i!=1&&a[i]!=a[i-1]){				b=false;			}			if(a[i]==1){				c=true;			}		}		if(b){			cout<<0<<'\n';			continue;		}		if(c){			cout<<-1<<'\n';			continue;		}				int cnt=0;		for(int k=1;k<=30;k++){			for(int i=1;i<=n;i++){				for(int j=1;j<=n;j++){					if(a[i]>a[j]){						cnt++;						ans[cnt][0]=i;						ans[cnt][1]=j;						if(a[i]%a[j]==0){							a[i]=a[i]/a[j];						}else{							a[i]=(a[i]/a[j])+1;						}											}				}			}		}		cout<<cnt<<'\n';		for(int i=1;i<=cnt;i++){			cout<<ans[i][0]<<" "<<ans[i][1]<<'\n';		}	}    return 0;}